"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[1178],{3497(e,t,a){a.r(t),a.d(t,{comp:()=>i,data:()=>o});var r=a(641);const n={},i=(0,a(6262).A)(n,[["render",function(e,t){return(0,r.uX)(),(0,r.CE)("div",null,[...t[0]||(t[0]=[(0,r.Fv)('<h1 id="wallet-auto-charge" tabindex="-1"><a class="header-anchor" href="#wallet-auto-charge"><span>Wallet Auto-Charge</span></a></h1><p>Automatically debit a winning bidder&#39;s wallet when their auction closes — no checkout flow needed.</p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-wallet-2.png" alt="Admin Wallet — per-user balances and ledger; auto-charge debits land here when an auction closes"></p><h2 id="what-it-does" tabindex="-1"><a class="header-anchor" href="#what-it-does"><span>What it does</span></a></h2><p>When an auction closes with a winner and <strong>auto-charge winner</strong> is on:</p><ol><li>The plugin reads the winner&#39;s wallet balance.</li><li>If the balance covers the winning bid, it debits the wallet for the bid amount.</li><li>A WooCommerce order is created automatically and marked complete.</li><li>The auction status flips directly to <em>paid</em>.</li><li>The customer receives an &quot;Auction won (wallet-paid)&quot; email.</li></ol><p>If the balance is short, the system falls back to the regular &quot;Auction won, please pay&quot; flow.</p><h2 id="why-use-it" tabindex="-1"><a class="header-anchor" href="#why-use-it"><span>Why use it</span></a></h2><table><thead><tr><th>Benefit</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Zero-friction win</strong></td><td>Customer doesn&#39;t have to do anything to claim their lot</td></tr><tr><td><strong>Higher conversion</strong></td><td>No &quot;winner ghosted&quot; cycle — paid the moment they won</td></tr><tr><td><strong>Faster fulfilment</strong></td><td>Order is complete immediately; warehouse can ship same-day</td></tr><tr><td><strong>Reduced support</strong></td><td>No &quot;I won but can&#39;t pay&quot; tickets</td></tr></tbody></table><p>Best for stores with engaged repeat customers who maintain a wallet balance.</p><h2 id="configure" tabindex="-1"><a class="header-anchor" href="#configure"><span>Configure</span></a></h2><p><strong>Auctions → Settings → Payments → Auto-charge winner</strong> — toggle on.</p><p>Once enabled it applies to every auction site-wide. A per-auction override is available on the <a href="/admin-add-auction.html" target="_blank" rel="noopener noreferrer">Add / Edit Auction</a> form.</p><h2 id="insufficient-balance" tabindex="-1"><a class="header-anchor" href="#insufficient-balance"><span>Insufficient balance</span></a></h2><p>If the winner&#39;s balance is below the winning bid, you have three behaviours to choose from:</p><table><thead><tr><th>Behaviour</th><th>When to use it</th></tr></thead><tbody><tr><td><strong>Charge what&#39;s available, request rest</strong></td><td>Wallet is debited up to the available balance; the remainder becomes an unpaid order</td></tr><tr><td><strong>Fall back to checkout</strong> (default)</td><td>Standard &quot;Auction won, please pay&quot; email goes out for the full amount</td></tr><tr><td><strong>Auto-relist immediately</strong></td><td>Skip checkout entirely and trigger <a href="/auto-relist.html" target="_blank" rel="noopener noreferrer">auto-relist</a> right away</td></tr></tbody></table><h2 id="order-details" tabindex="-1"><a class="header-anchor" href="#order-details"><span>Order details</span></a></h2><p>The auto-created order has:</p><table><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Status</td><td>Completed</td></tr><tr><td>Payment method</td><td>Wallet</td></tr><tr><td>Currency</td><td>Your site currency</td></tr><tr><td>Line items</td><td>1 × auction product at the winning bid amount</td></tr><tr><td>Customer</td><td>The winner</td></tr><tr><td>Billing / shipping</td><td>From the customer&#39;s profile</td></tr></tbody></table><p>The order appears in the customer&#39;s regular <strong>My Account → Orders</strong> list.</p><h2 id="refunds" tabindex="-1"><a class="header-anchor" href="#refunds"><span>Refunds</span></a></h2><p>If the auction is cancelled or disputed after auto-charge:</p><ol><li>Admin clicks <strong>Refund to wallet</strong> on the order.</li><li>The original debit is reversed with a fresh credit row in the ledger.</li><li>The customer receives a &quot;Wallet refunded&quot; email.</li></ol><p>The original debit row is preserved for traceability — refunds are written as an offset, never as a delete.</p><h2 id="notifications" tabindex="-1"><a class="header-anchor" href="#notifications"><span>Notifications</span></a></h2><table><thead><tr><th>Trigger</th><th>Email</th></tr></thead><tbody><tr><td>Auto-charge succeeded</td><td>&quot;Congratulations — auction won (paid from wallet)&quot;</td></tr><tr><td>Auto-charge failed (low balance)</td><td>Standard &quot;Auction won — please pay&quot;</td></tr><tr><td>Refund issued</td><td>&quot;Wallet refunded for auction #N&quot;</td></tr></tbody></table><h2 id="reporting" tabindex="-1"><a class="header-anchor" href="#reporting"><span>Reporting</span></a></h2><p><a href="/admin-reports.html#payment-status" target="_blank" rel="noopener noreferrer">Reports → Payment status</a> tracks:</p><ul><li>Auto-charge success rate (% of wins paid via wallet)</li><li>Auto-charge failure rate (% with insufficient balance)</li><li>Average wallet balance among winners (predictor of auto-charge success)</li></ul><h2 id="use-cases" tabindex="-1"><a class="header-anchor" href="#use-cases"><span>Use cases</span></a></h2><h3 id="frequent-bidder-rewards" tabindex="-1"><a class="header-anchor" href="#frequent-bidder-rewards"><span>&quot;Frequent-bidder rewards&quot;</span></a></h3><p>Encourage customers to maintain a wallet balance:</p><ul><li>Free top-up bonus (e.g. add $20 → get $25)</li><li>Discount on auction fees when paying from wallet</li><li>Loyalty points for wallet-paid wins</li></ul><p>Combined with auto-charge, this creates a tight engagement loop: customer tops up → wins auctions → tops up again.</p><h3 id="b2b-vendor-marketplace" tabindex="-1"><a class="header-anchor" href="#b2b-vendor-marketplace"><span>&quot;B2B / vendor marketplace&quot;</span></a></h3><p>Auctioning to known business buyers:</p><ul><li>Pre-funded wallets with credit terms</li><li>Auto-charge ensures bid commitments are fulfilled</li><li>Disputes are rare since business buyers are vetted</li></ul><h3 id="charity-event" tabindex="-1"><a class="header-anchor" href="#charity-event"><span>&quot;Charity event&quot;</span></a></h3><p>Auto-charge ensures donations are collected immediately:</p><ul><li>Reduces post-event collection workload</li><li>Tax receipts can be issued instantly (since payment is confirmed)</li><li>Higher net donations (no &quot;we&#39;ll pay later&quot; friction)</li></ul><p><a href="/auction-types.html#charity" target="_blank" rel="noopener noreferrer">Charity auctions →</a></p><h2 id="edge-cases" tabindex="-1"><a class="header-anchor" href="#edge-cases"><span>Edge cases</span></a></h2><table><thead><tr><th>Scenario</th><th>Behaviour</th></tr></thead><tbody><tr><td>Winner deleted before close</td><td>Auto-charge skipped; auction marked failed</td></tr><tr><td>Wallet disabled site-wide</td><td>Auto-charge disabled implicitly</td></tr><tr><td>Winner is admin / system user</td><td>Skipped (admins can&#39;t auto-charge themselves)</td></tr><tr><td>Multi-currency mismatch</td><td>Skipped; falls back to manual checkout</td></tr><tr><td>Concurrent auction wins</td><td>Sequential — the first win locks the wallet, the second checks the remaining balance</td></tr></tbody></table><h2 id="common-questions" tabindex="-1"><a class="header-anchor" href="#common-questions"><span>Common questions</span></a></h2><p><strong>&quot;What if the user wants to use a different payment method?&quot;</strong></p><p>By default, auto-charge runs unconditionally when the balance is sufficient. To allow opt-out, surface a per-auction toggle (&quot;Pay manually instead of auto-charging&quot;).</p><p><strong>&quot;Can I auto-charge to a saved card instead of wallet?&quot;</strong></p><p>That requires a different mechanism — see <a href="/stripe-connect.html" target="_blank" rel="noopener noreferrer">Stripe Connect</a> for card-on-file auto-charge.</p><p><strong>&quot;What about taxes / shipping?&quot;</strong></p><p>Auto-charge debits the <strong>winning bid amount</strong> only. Taxes and shipping are handled by the auto-created order using your standard WooCommerce tax and shipping configuration. If shipping needs customer input, the order may be created as <em>pending</em> instead of <em>complete</em>.</p>',50)])])}]]),o=JSON.parse('{"path":"/wallet-auto-charge.html","title":"Wallet Auto-Charge","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"What it does","slug":"what-it-does","link":"#what-it-does","children":[]},{"level":2,"title":"Why use it","slug":"why-use-it","link":"#why-use-it","children":[]},{"level":2,"title":"Configure","slug":"configure","link":"#configure","children":[]},{"level":2,"title":"Insufficient balance","slug":"insufficient-balance","link":"#insufficient-balance","children":[]},{"level":2,"title":"Order details","slug":"order-details","link":"#order-details","children":[]},{"level":2,"title":"Refunds","slug":"refunds","link":"#refunds","children":[]},{"level":2,"title":"Notifications","slug":"notifications","link":"#notifications","children":[]},{"level":2,"title":"Reporting","slug":"reporting","link":"#reporting","children":[]},{"level":2,"title":"Use cases","slug":"use-cases","link":"#use-cases","children":[{"level":3,"title":"\\"Frequent-bidder rewards\\"","slug":"frequent-bidder-rewards","link":"#frequent-bidder-rewards","children":[]},{"level":3,"title":"\\"B2B / vendor marketplace\\"","slug":"b2b-vendor-marketplace","link":"#b2b-vendor-marketplace","children":[]},{"level":3,"title":"\\"Charity event\\"","slug":"charity-event","link":"#charity-event","children":[]}]},{"level":2,"title":"Edge cases","slug":"edge-cases","link":"#edge-cases","children":[]},{"level":2,"title":"Common questions","slug":"common-questions","link":"#common-questions","children":[]}],"git":{},"filePathRelative":"wallet-auto-charge.md"}')}}]);